// ============================================================
// CHUNKER SEMÁNTICO MEJORADO - Context Engineering
// Genera chunks tipados con metadata rica para retrieval
// ============================================================

const body = $('Webhook omghat1').item.json.body;
const slug = body.agent_id;
const agentName = body.agent_name;
const tone = body.tone;
const prompt = body.prompt;
const faqs = body.faqs || [];
const escalationPhone = body.escalation_phone;
const adminPhone = body.admin_phone;
const images = body.images || [];
const catalogs = body.catalogs || [];

function splitText(texto, maxLen) {
  const partes = [];
  let inicio = 0;
  while (inicio < texto.length) {
    let fin = inicio + maxLen;
    if (fin >= texto.length) { partes.push(texto.substring(inicio).trim()); break; }
    let corte = texto.lastIndexOf(' ', fin);
    if (corte <= inicio) corte = fin;
    partes.push(texto.substring(inicio, corte).trim());
    inicio = corte + 1;
  }
  return partes.filter(p => p.length > 0);
}

const chunks = [];

// ── 1. IDENTIDAD ──
chunks.push({
  text: `IDENTIDAD DEL NEGOCIO: ${agentName}. ${prompt.substring(0, 300).replace(/\n/g, ' ')}`,
  id: `identidad_${slug}_001`,
  tipo: 'identidad',
  categoria: 'identidad',
  relevancia: 1.0,
  uso: 'primer_contacto',
  trigger_keywords: 'saludo,hola,buenos dias,quién,qué es,información'
});

// ── 2. PRODUCTOS/SERVICIOS ──
// Detectar bloques de productos por patrones de precio
const precioRegex = /●?\s*([A-ZÁÉÍÓÚa-záéíóúñÑ][A-ZÁÉÍÓÚa-záéíóúñÑ\s]+?)\s*[–—-]\s*\$([0-9.,]+)/g;
let match;
const productos = [];
while ((match = precioRegex.exec(prompt)) !== null) {
  productos.push({ nombre: match[1].trim(), precio: match[2].trim() });
}

// Si detectó productos, crear un chunk por cada uno o agrupados
if (productos.length > 0) {
  // Chunk de resumen de tarifas
  const resumenTarifas = productos.map(p => `${p.nombre}: $${p.precio}`).join('. ');
  chunks.push({
    text: `TARIFAS Y PRECIOS DE ${agentName}: ${resumenTarifas}`,
    id: `producto_tarifas_${slug}_001`,
    tipo: 'producto',
    categoria: 'producto',
    relevancia: 1.0,
    uso: 'consulta_precios',
    trigger_keywords: 'precio,tarifa,cuánto,cuesta,valor,opciones,alojamiento'
  });
}

// ── 3. SECCIONES DEL PROMPT COMO CONOCIMIENTO TÉCNICO ──
// Detectar secciones numeradas del prompt
const seccionRegex = /(?:🟢\s*)?\d+\.\s*([^\n]+)([\s\S]*?)(?=(?:🟢\s*)?\d+\.|$)/g;
let secMatch;
const secciones = [];
while ((secMatch = seccionRegex.exec(prompt)) !== null) {
  secciones.push({
    titulo: secMatch[1].trim(),
    contenido: secMatch[2].trim()
  });
}

if (secciones.length > 0) {
  secciones.forEach((sec, i) => {
    if (sec.contenido.length < 20) return;
    const partes = splitText(sec.contenido, 600);
    partes.forEach((parte, k) => {
      // Detectar tipo por título
      let tipo = 'conocimiento';
      let trigger = '';
      const tituloLower = sec.titulo.toLowerCase();

      if (tituloLower.includes('bienvenida') || tituloLower.includes('inicial')) {
        tipo = 'flujo_bienvenida';
        trigger = 'hola,buenos,primera vez,saludo';
      } else if (tituloLower.includes('ubicac')) {
        tipo = 'ubicacion';
        trigger = 'dónde,ubicación,dirección,cómo llego,mapa';
      } else if (tituloLower.includes('tarifa') || tituloLower.includes('precio')) {
        tipo = 'producto';
        trigger = 'precio,tarifa,cuánto,cuesta,valor';
      } else if (tituloLower.includes('capacidad')) {
        tipo = 'producto';
        trigger = 'capacidad,personas,cuántos,parejas,familiar';
      } else if (tituloLower.includes('reserv')) {
        tipo = 'proceso';
        trigger = 'reservar,apartar,pagar,abono,cuenta';
      } else if (tituloLower.includes('polít')) {
        tipo = 'politica';
        trigger = 'devolución,cancelar,cambio,política';
      } else if (tituloLower.includes('cierre')) {
        tipo = 'flujo_cierre';
        trigger = 'gracias,listo,perfecto,cierre';
      } else if (tituloLower.includes('descuento') || tituloLower.includes('semana')) {
        tipo = 'producto';
        trigger = 'descuento,promoción,entre semana,oferta';
      }

      chunks.push({
        text: `${sec.titulo.toUpperCase()}: ${parte}`,
        id: `conocimiento_${slug}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo,
        categoria: tipo,
        relevancia: 0.95,
        uso: `seccion_${sec.titulo.toLowerCase().replace(/[^a-z0-9]/g,'_').substring(0,30)}`,
        trigger_keywords: trigger
      });
    });
  });
} else {
  // Fallback: dividir por párrafos
  const parrafos = prompt.split(/\n{2,}/).map(s => s.trim()).filter(s => s.length > 30);
  parrafos.forEach((parr, i) => {
    splitText(parr, 600).forEach((parte, k) => {
      chunks.push({
        text: parte,
        id: `conocimiento_${slug}_p${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: 'conocimiento',
        categoria: 'conocimiento',
        relevancia: 0.9,
        uso: `parrafo_${i+1}`,
        trigger_keywords: ''
      });
    });
  });
}

// ── 4. FAQs ──
faqs.forEach((faq, i) => {
  if (!faq.question || !faq.answer || faq.answer.length < 3) return;
  chunks.push({
    text: `PREGUNTA FRECUENTE: ${faq.question} RESPUESTA: ${faq.answer}`,
    id: `faq_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'faq',
    categoria: 'faq',
    relevancia: 0.9,
    uso: 'faq_general',
    trigger_keywords: faq.question.toLowerCase().replace(/[¿?]/g, '').substring(0, 60)
  });
});

// ── 5. ESCALAMIENTO ──
chunks.push({
  text: `PROTOCOLO DE ESCALAMIENTO: Responder con action "escalate" cuando: cliente confirma intención de pago o reserva, cliente pide hablar con humano, cliente reclama pedido anterior, la base de conocimiento no resuelve tras 1 intento, frustración en 3+ mensajes consecutivos, lenguaje ofensivo por segunda vez. Teléfono escalamiento: ${escalationPhone}. Teléfono admin: ${adminPhone}. NO escalar por: saludos, preguntas de info, precios, catálogo, ubicación, políticas generales.`,
  id: `escalamiento_${slug}_001`,
  tipo: 'procedimiento',
  categoria: 'escalamiento',
  relevancia: 1.0,
  uso: 'escalamiento',
  trigger_keywords: 'humano,persona,queja,reclamo,pagar,reservar,frustrado,enojado'
});

// ── 6. MEDIA - IMÁGENES ──
images.forEach((img, i) => {
  chunks.push({
    text: `IMAGEN DISPONIBLE: ${img.name}. Cuando el cliente pregunte por ${img.name} o quiera ver fotos, responde con action "image" y media array incluyendo {"type":"image","url":"${img.url}","caption":"${img.name}"}`,
    id: `media_img_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'media',
    categoria: 'media_imagen',
    relevancia: 0.9,
    uso: `visual_${img.name.toLowerCase().replace(/\s+/g,'_')}`,
    trigger_keywords: `${img.name.toLowerCase()},foto,imagen,ver,mostrar`
  });
});

// ── 7. MEDIA - CATÁLOGOS ──
catalogs.forEach((doc, i) => {
  const fileName = doc.fileName || doc.url.split('/').pop();
  chunks.push({
    text: `DOCUMENTO DISPONIBLE: ${doc.name}. Cuando el cliente pida catálogo, precios o documentación, responde con action "document" y media array incluyendo {"type":"document","url":"${doc.url}","caption":"${doc.name}"}`,
    id: `media_doc_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'media',
    categoria: 'media_documento',
    relevancia: 0.9,
    uso: `documento_${doc.name.toLowerCase().replace(/\s+/g,'_')}`,
    trigger_keywords: `${doc.name.toLowerCase()},catálogo,documento,pdf,lista,precios`
  });
});

// ── 8. TONO Y PERSONALIDAD ──
const tonoDescripcion = {
  friendly: 'Tutea al cliente, sé cálido, cercano, colombiano natural. Usa emojis con moderación.',
  formal: 'Trata de usted, sé profesional y serio. No uses emojis.',
  casual: 'Sé relajado, usa emojis, lenguaje coloquial colombiano.',
  empathetic: 'Sé comprensivo, valida las emociones del cliente, ten paciencia.',
  enthusiastic: 'Sé energético, usa exclamaciones, motiva al cliente.'
};

chunks.push({
  text: `PERSONALIDAD Y TONO: Tono configurado: ${tone}. ${tonoDescripcion[tone] || tonoDescripcion.friendly}. Español colombiano, buena ortografía. Si no sabes algo responde: déjame verificar eso con mi equipo. Formato: texto plano para WhatsApp, prohibido markdown.`,
  id: `personalidad_${slug}_001`,
  tipo: 'personalidad',
  categoria: 'personalidad',
  relevancia: 1.0,
  uso: 'tono_estilo',
  trigger_keywords: ''
});

return chunks.map(chunk => ({ json: chunk }));

