DO $$
DECLARE
  v_agent_id TEXT := '{{ $("Telefonos").item.json.agent_id }}';
  v_admin TEXT := '{{ $("Telefonos").item.json.escalation_phone }}';
  v_escal TEXT := '{{ $("Telefonos").item.json.admin_phone }}';
  v_waba TEXT := '{{ $("Telefonos").item.json.waba_id }}';
  v_phones JSONB := '{{ JSON.stringify($("Telefonos").item.json.phones_list) }}'::jsonb;
BEGIN
  IF v_waba IS NOT NULL AND v_waba != '' THEN
    -- Try update existing row by waba_id
    UPDATE agent_phones
    SET agent_id = v_agent_id,
        escalation_phone = v_escal,
        admin_phone = v_admin,
        phones_list = v_phones,
        updated_at = NOW()
    WHERE waba_id = v_waba;

    -- If no row updated, insert new
    IF NOT FOUND THEN
      INSERT INTO agent_phones (agent_id, escalation_phone, admin_phone, phones_list, waba_id)
      VALUES (v_agent_id, v_escal, v_admin, v_phones, v_waba);
    END IF;
  ELSE
    -- No waba_id: upsert by agent_id
    UPDATE agent_phones
    SET escalation_phone = v_escal,
        admin_phone = v_admin,
        phones_list = v_phones,
        updated_at = NOW()
    WHERE agent_id = v_agent_id AND (waba_id IS NULL OR waba_id = '');

    IF NOT FOUND THEN
      INSERT INTO agent_phones (agent_id, escalation_phone, admin_phone, phones_list)
      VALUES (v_agent_id, v_escal, v_admin, v_phones);
    END IF;
  END IF;
END $$;

