    partes.forEach((parte, k) => {
      // Detectar tipo por título
      let tipo = 'conocimiento';
      let trigger = '';
      const tituloLower = sec.titulo.toLowerCase();

      if (tituloLower.includes('bienvenida') || tituloLower.includes('inicial')) {
        tipo = 'flujo_bienvenida';
        trigger = 'hola,buenos,primera vez,saludo';
      } else if (tituloLower.includes('ubicac')) {
        tipo = 'ubicacion';
        trigger = 'dónde,ubicación,dirección,cómo llego,mapa';
      } else if (tituloLower.includes('tarifa') || tituloLower.includes('precio')) {
        tipo = 'producto';
        trigger = 'precio,tarifa,cuánto,cuesta,valor';
      } else if (tituloLower.includes('capacidad')) {
        tipo = 'producto';
        trigger = 'capacidad,personas,cuántos,parejas,familiar';
      } else if (tituloLower.includes('reserv')) {
        tipo = 'proceso';
        trigger = 'reservar,apartar,pagar,abono,cuenta';
      } else if (tituloLower.includes('polít')) {
        tipo = 'politica';
        trigger = 'devolución,cancelar,cambio,política';
      } else if (tituloLower.includes('cierre')) {
        tipo = 'flujo_cierre';
        trigger = 'gracias,listo,perfecto,cierre';
      } else if (tituloLower.includes('descuento') || tituloLower.includes('semana')) {
        tipo = 'producto';
        trigger = 'descuento,promoción,entre semana,oferta';
      }

      chunks.push({
        text: `${sec.titulo.toUpperCase()}: ${parte}`,
        id: `conocimiento_${slug}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
