        relevancia: 0.95,
        uso: `seccion_${sec.titulo.toLowerCase().replace(/[^a-z0-9]/g,'_').substring(0,30)}`,
        trigger_keywords: trigger
      });
    });
  });
} else {
  // Fallback: dividir por párrafos
  const parrafos = prompt.split(/\n{2,}/).map(s => s.trim()).filter(s => s.length > 30);
  parrafos.forEach((parr, i) => {
    splitText(parr, 600).forEach((parte, k) => {
      chunks.push({
        text: parte,
        id: `conocimiento_${slug}_p${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: 'conocimiento',
        categoria: 'conocimiento',
        relevancia: 0.9,
        uso: `parrafo_${i+1}`,
        trigger_keywords: ''
      });
    });
  });
}

// ── 4. FAQs ──
faqs.forEach((faq, i) => {
  if (!faq.question || !faq.answer || faq.answer.length < 3) return;
  chunks.push({
    text: `PREGUNTA FRECUENTE: ${faq.question} RESPUESTA: ${faq.answer}`,
    id: `faq_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'faq',
